namespace Database\Factories;use App\Domain\Hunts\Sessions\HuntingSessionMode;use App\Domain\Hunts\Sessions\HuntingSessionStatus;use App\Models\Character;use App\Models\HuntingSession;use App\Models\Zone;use Illuminate\Database\Eloquent\Factories\Factory;class HuntingSessionFactory extends Factory{protected $model=HuntingSession::class;public function definition(){return['character_id'=>Character::factory(),'zone_id'=>Zone::query()->value('id'),'mode'=>HuntingSessionMode::CONNECTED,'status'=>HuntingSessionStatus::RUNNING,'stop_reason'=>null,'consecutive_defeats'=>0,'hunts_count'=>0,'victories_count'=>0,'defeats_count'=>0,'draws_count'=>0,'next_encounter_at'=>now(),'last_heartbeat_at'=>now(),'started_at'=>now(),'stopped_at'=>null];}public function stopped($reason='user_stopped'){return$this->state(function()use($reason){return['status'=>'stopped','stop_reason'=>$reason,'next_encounter_at'=>null,'stopped_at'=>now()];});}}
